from typing import List, Optional

class ListNode:
    def __init__(self, val=0, next=None):
        self.val = val
        self.next = next

def build_list_with_cycle(nums: List[int], pos: int) -> Optional[ListNode]:
    if not nums:
        return None
    nodes = [ListNode(n) for n in nums]
    for i in range(len(nodes) - 1):
        nodes[i].next = nodes[i + 1]
    if pos >= 0:
        nodes[-1].next = nodes[pos]
    return nodes[0]

def has_cycle(head: List[int], pos: int) -> bool:
    node = build_list_with_cycle(head, pos)
    slow = node
    fast = node

    while fast and fast.next:
        slow = slow.next
        fast = fast.next.next
        if slow is fast:
            return True

    return False

